angular.module('dpClient.helpers')
    .directive('wcga', function () {
        return {
            restrict: 'E',
            scope: {},
            replace: true,
            templateUrl: 'src/index/templates/wcga.html',
            controller: function ($scope, localStorageService, SettingService) {

                var Setting = new SettingService('additionalSettings');
                Setting.getPublicSettings().then(function (settingsData) {
                    $scope.wcgaUsed = settingsData.wcgaUsed.value;
                    if($scope.wcgaUsed){
                        const lsKeys = localStorageService.keys()

                        if (lsKeys.indexOf('wcgaKontrast') > -1) {
                            $('body').addClass('wcga-contrast')
                        }

                        if (lsKeys.indexOf('wcgaFonts') > -1) {
                            $('body').addClass('wcga-fonts')
                        }
                    }
                });

                $scope.changeContrast = () => {
                    $('body').toggleClass('wcga-contrast');
                    if ($('body').hasClass('wcga-contrast')) {
                        localStorageService.set('wcgaKontrast', 1)
                    } else {
                        localStorageService.remove('wcgaKontrast')
                    }
                }

                $scope.toggleFontSize = () => {
                    $('body').toggleClass('wcga-fonts')
                    if ($('body').hasClass('wcga-fonts')) {
                        localStorageService.set('wcgaFonts', 1)
                    } else {
                        localStorageService.remove('wcgaFonts')
                    }
                }

            }
        }
    })

angular.module('dpClient.app')
    .controller('index.SitemapCtrl', function( $scope, $rootScope, routes, DpCategoryService, $q ) {

        $scope.sites = [];
        $scope.menuItems = [];

        var parentAvailable = ['sitemap', 'cart','attribute-filters'];

        $rootScope.$watch('menuItems', function( data ) {
            if( data !== undefined ) {
                $scope.menuItems = data;
            }
        });

        function init() {

            routes.getAll().then( function(routeData) {
                if( routeData.data ) {
                    _.each(routeData.data, function(one, index) {
                        if( one.route.parent === 'home' &&
                            one.route.abstract === 0 &&
                            parentAvailable.indexOf(one.route.state) > -1 ) {
                            $scope.sites.push(one.route);
                        } else if( one.route.parent === 'staticPages' ) {
                            $scope.sites.push(one.route);
                        }
                    });

                    getGroups().then( function(groupsData) {

                        //$scope.sites.groups = groupsData;

                        getItems().then(function (itemsData) {

                            _.each(itemsData, function (parentCategory) {

                                $scope.sites.push({
                                    state: 'category',
                                    langs: parentCategory.langs,
                                    children: parentCategory.childs,
                                    //groups: groupsData[parentCategory.ID],
                                    types: parentCategory.types
                                });


                                _.each(parentCategory.childs, function(child) {

                                    //child.groups =  groupsData[child.ID];

                                });

                            });
                        });
                    });

                }
            });

        }

        function getItems() {
            var def = $q.defer();

            var timeHandler = setTimeout(function(){
                if( $scope.menuItems !== undefined ) {
                    def.resolve($scope.menuItems);
                    clearTimeout(timeHandler);
                }
            }, 1000);

            return def.promise;
        }

        function getGroups() {
            var def = $q.defer();

            DpCategoryService.getGroups().then(function(data) {
                def.resolve(data);
            });

            return def.promise;
        }

        init();

    })

